#include<bits/stdc++.h>
using namespace std;
int n;
int main() {
    ios::sync_with_stdio(false); cin.tie(NULL); cout.tie(NULL);
	int a, maxx = -100000000, dp;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a;
		if (i == 1) {
			dp = a;
		} else {
			dp = max(a, dp + a);
		}
		maxx = max(maxx, dp);
	}
	cout << maxx;
}
